{
  "name": "Customer Journey Playground",
  "description": "An interactive tool for business owners to simulate AI-powered customer journeys, highlighting time savings and revenue growth through automation.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type BusinessType = 'Clinic' | 'Salon' | 'Rentals' | 'Mechanic' | 'Coaching' | 'Restaurant';

export type EntryPoint = 
  | 'Google Maps "Call Now"'
  | 'Website Chat'
  | 'Website Contact Form'
  | 'WhatsApp Message'
  | 'Instagram DM'
  | 'Referral Call';

export type Intent = 
  | 'Book Appointment'
  | 'Ask a Question'
  | 'Get a Quote'
  | 'Pay / Deposit'
  | 'Reschedule / Cancel';

export interface ChatMessage {
  sender: 'customer' | 'ai';
  text: string;
}

export interface SimulationScenario {
  id: string;
  businessType: BusinessType;
  entryPoint: EntryPoint;
  intent: Intent;
  conversation: ChatMessage[];
  aiActions: string[];
  manualTasks: string[];
  metrics: {
    minutesSaved: number;
    missedCallRecovery: boolean;
    revenuePotential: number;
  };
}

export interface UserMetrics {
  avgBookingValue: number;
  leadsPerWeek: number;
  missedCallsPerWeek: number;
}

import { SimulationScenario } from '../types';

export const SCENARIOS: SimulationScenario[] = [
  {
    id: '1',
    businessType: 'Clinic',
    entryPoint: 'Google Maps "Call Now"',
    intent: 'Book Appointment',
    conversation: [
      { sender: 'customer', text: 'Hi, I saw you on Maps. Do you have any openings for a physio session this afternoon?' },
      { sender: 'ai', text: 'Hi there! We have two slots left today at 3:30 PM and 5:00 PM. Would either of those work for you?' },
      { sender: 'customer', text: '3:30 PM is perfect. Do I need to bring anything?' },
      { sender: 'ai', text: 'Great! Just bring any previous scans if you have them. I\'ve reserved 3:30 PM for you. I\'m sending a secure link now to confirm your details and take a small deposit.' },
      { sender: 'customer', text: 'Done! Thanks.' },
      { sender: 'ai', text: 'Received! You\'re all set. I\'ll send you a reminder 2 hours before your appointment. See you at 3:30!' }
    ],
    aiActions: [
      'Instant voice-to-text response',
      'Live calendar availability check',
      'Dynamic qualification (scans/info)',
      'Secure deposit link generation',
      'Automated confirmation SMS',
      'Reminder sequence scheduled'
    ],
    manualTasks: [
      'Stop work to answer the phone',
      'Check paper/digital diary',
      'Ask for patient details',
      'Manually type out deposit link',
      'Chase for confirmation',
      'Write down reminder to call them back'
    ],
    metrics: {
      minutesSaved: 15,
      missedCallRecovery: true,
      revenuePotential: 85
    }
  },
  {
    id: '2',
    businessType: 'Salon',
    entryPoint: 'Instagram DM',
    intent: 'Book Appointment',
    conversation: [
      { sender: 'customer', text: 'Hey! Love your latest post. How much for a full balayage next Saturday?' },
      { sender: 'ai', text: 'Thank you! A full balayage starts at €120. To give you an exact quote, is your hair currently colored or natural?' },
      { sender: 'customer', text: 'It\'s natural, about shoulder length.' },
      { sender: 'ai', text: 'Perfect. For natural shoulder-length hair, it\'ll be €125. We have a 10:00 AM slot next Saturday. Should I grab it for you?' },
      { sender: 'customer', text: 'Yes please!' },
      { sender: 'ai', text: 'Booked! You\'ll get a text confirmation in a second. We look forward to seeing you!' }
    ],
    aiActions: [
      '24/7 DM Monitoring',
      'Instant pricing lookup',
      'Hair type qualification',
      'Calendar syncing',
      'Automatic follow-up trigger'
    ],
    manualTasks: [
      'Checking DMs after hours',
      'Calculating individual quotes',
      'Back-and-forth on dates',
      'Manual entry into booking app',
      'Sending manual texts'
    ],
    metrics: {
      minutesSaved: 20,
      missedCallRecovery: false,
      revenuePotential: 125
    }
  },
  {
    id: '3',
    businessType: 'Rentals',
    entryPoint: 'WhatsApp Message',
    intent: 'Get a Quote',
    conversation: [
      { sender: 'customer', text: 'Hi, looking to rent the mountain bikes for a group of 6 this weekend.' },
      { sender: 'ai', text: 'Hi! We can definitely help with that. Which day are you looking at, and for how many hours?' },
      { sender: 'customer', text: 'Saturday morning, maybe 4 hours.' },
      { sender: 'ai', text: 'Saturday is busy but we have 6 bikes available from 9 AM. Total for 6 bikes for 4 hours is €180. Want me to send the booking link?' },
      { sender: 'customer', text: 'Yes, please.' }
    ],
    aiActions: [
      'Real-time inventory check',
      'Group discount calculation',
      'Upsell safety gear',
      'Digital waiver delivery',
      'Instant payment link'
    ],
    manualTasks: [
      'Count physical stock',
      'Calculate group rates',
      'Check availability against returns',
      'Paperwork prep',
      'Taking card details over phone'
    ],
    metrics: {
      minutesSaved: 25,
      missedCallRecovery: false,
      revenuePotential: 180
    }
  },
  {
    id: '4',
    businessType: 'Mechanic',
    entryPoint: 'Referral Call',
    intent: 'Get a Quote',
    conversation: [
      { sender: 'customer', text: 'Hey, my friend Dave said you guys are great. My brakes are squeaking really loudly.' },
      { sender: 'ai', text: 'Dave is a regular! Squeaking usually means pads or rotors. What\'s the make and model of your car?' },
      { sender: 'customer', text: 'It\'s a 2018 VW Golf.' },
      { sender: 'ai', text: 'Got it. Usually €150-€200 for pads. Can you drop it off Thursday at 8 AM for a 15-min inspection?' },
      { sender: 'customer', text: 'I can do Friday instead?' },
      { sender: 'ai', text: 'Friday at 8 AM works too. I\'ve noted you as Dave\'s referral. See you then!' }
    ],
    aiActions: [
      'Voice-to-CRM logging',
      'Referral source tracking',
      'Parts pricing database check',
      'Drop-off window management',
      'Automatic location sharing'
    ],
    manualTasks: [
      'Answering phone with greasy hands',
      'Searching for "Dave" in records',
      'Estimating parts on the fly',
      'Writing down plate numbers',
      'Giving directions over phone'
    ],
    metrics: {
      minutesSaved: 12,
      missedCallRecovery: true,
      revenuePotential: 200
    }
  }
];

// Helper to find or generate a scenario fallback
export const getScenario = (business: string, entry: string, intent: string): SimulationScenario => {
  const found = SCENARIOS.find(s => s.businessType === business && s.intent === intent);
  if (found) return found;

  // Generic fallback if no specific one matches (ensures the demo always works)
  return {
    ...SCENARIOS[0],
    businessType: business as any,
    entryPoint: entry as any,
    intent: intent as any,
  };
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  Building2, 
  MessageSquare, 
  Calendar, 
  Clock, 
  TrendingUp, 
  Zap, 
  Phone, 
  Mail, 
  MapPin, 
  RotateCcw,
  CheckCircle2,
  XCircle,
  ArrowRight,
  ShieldCheck,
  Instagram,
  Users
} from 'lucide-react';
import { BusinessType, EntryPoint, Intent, UserMetrics, SimulationScenario } from './types';
import { SCENARIOS, getScenario } from './constants/scenarios';

const App: React.FC = () => {
  // --- UI State ---
  const [activeStep, setActiveStep] = useState<number>(1);
  const [selectedBusiness, setSelectedBusiness] = useState<BusinessType | null>(null);
  const [selectedEntry, setSelectedEntry] = useState<EntryPoint | null>(null);
  const [selectedIntent, setSelectedIntent] = useState<Intent | null>(null);
  const [isSimulating, setIsSimulating] = useState(false);
  const [simStep, setSimStep] = useState(0);

  // --- Metrics State ---
  const [metrics, setMetrics] = useState<UserMetrics>({
    avgBookingValue: 85,
    leadsPerWeek: 20,
    missedCallsPerWeek: 5
  });

  const scenario = useMemo(() => {
    if (!selectedBusiness || !selectedEntry || !selectedIntent) return null;
    return getScenario(selectedBusiness, selectedEntry, selectedIntent);
  }, [selectedBusiness, selectedEntry, selectedIntent]);

  // --- Handlers ---
  const handleReset = () => {
    setActiveStep(1);
    setSelectedBusiness(null);
    setSelectedEntry(null);
    setSelectedIntent(null);
    setIsSimulating(false);
    setSimStep(0);
  };

  const startSimulation = () => {
    setIsSimulating(true);
    setSimStep(0);
  };

  useEffect(() => {
    if (isSimulating && scenario && simStep < scenario.conversation.length) {
      const timer = setTimeout(() => {
        setSimStep(prev => prev + 1);
      }, 1500);
      return () => clearTimeout(timer);
    }
  }, [isSimulating, simStep, scenario]);

  // --- ROI Calculation ---
  const calculatedStats = useMemo(() => {
    const weeklySavingsMinutes = metrics.leadsPerWeek * 15; // 15 mins avg per lead
    const recoveredRevenue = metrics.missedCallsPerWeek * 0.4 * metrics.avgBookingValue; // 40% recovery rate
    const monthlyRevenueImpact = (recoveredRevenue * 4) + (metrics.leadsPerWeek * metrics.avgBookingValue * 0.15 * 4); // 15% booking boost

    return {
      hoursSaved: Math.round(weeklySavingsMinutes / 60),
      revenueImpact: Math.round(monthlyRevenueImpact)
    };
  }, [metrics]);

  return (
    <div className="min-h-screen">
      {/* 1. HERO SECTION */}
      <header className="bg-white border-b border-slate-200">
        <div className="max-w-6xl mx-auto px-4 py-12 md:py-24 flex flex-col items-center text-center">
          <div className="inline-flex items-center space-x-2 bg-blue-50 text-blue-600 px-3 py-1 rounded-full text-sm font-semibold mb-6">
            <Zap size={16} />
            <span>AI Customer Engagement Platform</span>
          </div>
          <h1 className="text-4xl md:text-6xl font-extrabold tracking-tight text-slate-900 mb-6 max-w-4xl">
            See how customers find you — and how <span className="text-blue-600">AI handles the entire journey.</span>
          </h1>
          <p className="text-lg md:text-xl text-slate-600 mb-10 max-w-2xl">
            From first message to booking, payment, reminders, and follow-up — without you ever touching your phone.
          </p>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12 w-full max-w-4xl">
            <div className="flex items-center justify-center space-x-3 text-slate-700">
              <CheckCircle2 className="text-green-500" />
              <span className="font-medium">15+ hours saved/week</span>
            </div>
            <div className="flex items-center justify-center space-x-3 text-slate-700">
              <CheckCircle2 className="text-green-500" />
              <span className="font-medium">25% more bookings</span>
            </div>
            <div className="flex items-center justify-center space-x-3 text-slate-700">
              <CheckCircle2 className="text-green-500" />
              <span className="font-medium">90% fewer no-shows</span>
            </div>
          </div>

          <div className="flex flex-col sm:flex-row space-y-4 sm:space-y-0 sm:space-x-4">
            <a href="#demo" className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-4 rounded-xl font-bold text-lg shadow-lg shadow-blue-200 transition-all flex items-center justify-center">
              Try the Journey Demo
              <ArrowRight className="ml-2" size={20} />
            </a>
            <button className="bg-white border-2 border-slate-200 hover:border-slate-300 text-slate-700 px-8 py-4 rounded-xl font-bold text-lg transition-all">
              Get a Free Setup Audit
            </button>
          </div>
        </div>
      </header>

      {/* 2. INTERACTIVE JOURNEY PLAYGROUND */}
      <section id="demo" className="py-20 bg-slate-50">
        <div className="max-w-6xl mx-auto px-4">
          <div className="text-center mb-16">
            <h2 className="text-3xl font-bold mb-4">Journey Simulation Playground</h2>
            <p className="text-slate-600">Select your options below to see how AI handles your business workflow.</p>
          </div>

          <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-slate-200">
            {/* Steps Navigation */}
            <div className="bg-slate-50 border-b border-slate-200 flex overflow-x-auto no-scrollbar">
              {[
                { id: 1, label: 'Business Type' },
                { id: 2, label: 'Entry Point' },
                { id: 3, label: 'Customer Intent' },
                { id: 4, label: 'The Simulation' }
              ].map((step) => (
                <button
                  key={step.id}
                  onClick={() => step.id <= activeStep && setActiveStep(step.id)}
                  disabled={step.id > activeStep && !isSimulating}
                  className={`flex-1 min-w-[150px] py-4 px-6 text-sm font-semibold border-r border-slate-200 transition-all ${
                    activeStep === step.id 
                    ? 'bg-white text-blue-600 border-b-2 border-b-blue-600' 
                    : 'text-slate-400 cursor-default'
                  }`}
                >
                  Step {step.id}: {step.label}
                </button>
              ))}
            </div>

            <div className="p-8">
              {/* STEP 1: BUSINESS TYPE */}
              {activeStep === 1 && (
                <div className="grid grid-cols-2 md:grid-cols-3 gap-4 animate-in fade-in duration-500">
                  {['Clinic', 'Salon', 'Rentals', 'Mechanic', 'Coaching', 'Restaurant'].map((type) => (
                    <button
                      key={type}
                      onClick={() => {
                        setSelectedBusiness(type as BusinessType);
                        setActiveStep(2);
                      }}
                      className="p-6 border-2 border-slate-100 rounded-2xl hover:border-blue-500 hover:bg-blue-50 transition-all text-left flex flex-col items-center justify-center space-y-3 group"
                    >
                      <Building2 className="w-10 h-10 text-slate-400 group-hover:text-blue-600 transition-colors" />
                      <span className="font-bold text-lg text-slate-700">{type}</span>
                    </button>
                  ))}
                </div>
              )}

              {/* STEP 2: ENTRY POINT */}
              {activeStep === 2 && (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4 animate-in slide-in-from-right duration-500">
                  {[
                    { name: 'Google Maps "Call Now"', icon: MapPin },
                    { name: 'Website Chat', icon: MessageSquare },
                    { name: 'Website Contact Form', icon: Mail },
                    { name: 'WhatsApp Message', icon: Phone },
                    { name: 'Instagram DM', icon: Instagram },
                    { name: 'Referral Call', icon: Users }
                  ].map((entry) => (
                    <button
                      key={entry.name}
                      onClick={() => {
                        setSelectedEntry(entry.name as EntryPoint);
                        setActiveStep(3);
                      }}
                      className="p-6 border-2 border-slate-100 rounded-2xl hover:border-blue-500 hover:bg-blue-50 transition-all text-left flex items-start space-x-4 group"
                    >
                      <div className="bg-slate-100 p-3 rounded-lg group-hover:bg-blue-100">
                        <entry.icon className="w-6 h-6 text-slate-600 group-hover:text-blue-600" />
                      </div>
                      <div>
                        <span className="font-bold block text-slate-800">{entry.name}</span>
                        <span className="text-sm text-slate-500">Customer reaches out here</span>
                      </div>
                    </button>
                  ))}
                </div>
              )}

              {/* STEP 3: INTENT */}
              {activeStep === 3 && (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4 animate-in slide-in-from-right duration-500">
                  {['Book Appointment', 'Ask a Question', 'Get a Quote', 'Pay / Deposit', 'Reschedule / Cancel'].map((intent) => (
                    <button
                      key={intent}
                      onClick={() => {
                        setSelectedIntent(intent as Intent);
                        setActiveStep(4);
                        startSimulation();
                      }}
                      className="p-6 border-2 border-slate-100 rounded-2xl hover:border-blue-500 hover:bg-blue-50 transition-all text-center flex flex-col items-center justify-center space-y-3 group"
                    >
                      <Calendar className="w-8 h-8 text-slate-400 group-hover:text-blue-600" />
                      <span className="font-bold text-sm text-slate-800">{intent}</span>
                    </button>
                  ))}
                </div>
              )}

              {/* STEP 4: SIMULATION */}
              {activeStep === 4 && scenario && (
                <div className="space-y-8 animate-in zoom-in-95 duration-500">
                  <div className="flex justify-between items-center bg-blue-50 p-4 rounded-xl border border-blue-100">
                    <div>
                      <span className="text-sm text-blue-600 font-bold uppercase tracking-wider">Scenario</span>
                      <h3 className="text-lg font-bold text-slate-900">{scenario.businessType} via {scenario.entryPoint} for {scenario.intent}</h3>
                    </div>
                    <button onClick={handleReset} className="flex items-center text-slate-500 hover:text-slate-800 transition-colors">
                      <RotateCcw size={16} className="mr-1" />
                      <span className="text-sm font-medium">Reset Demo</span>
                    </button>
                  </div>

                  <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 h-[500px] overflow-hidden">
                    {/* COLUMN 1: CUSTOMER SEES */}
                    <div className="flex flex-col h-full bg-slate-50 rounded-2xl p-4 border border-slate-200">
                      <div className="flex items-center mb-4 space-x-2">
                        <MessageSquare size={18} className="text-slate-400" />
                        <h4 className="font-bold text-slate-700">Customer Interaction</h4>
                      </div>
                      <div className="flex-1 overflow-y-auto space-y-4 pr-2 custom-scrollbar">
                        {scenario.conversation.slice(0, simStep).map((msg, i) => (
                          <div key={i} className={`flex ${msg.sender === 'customer' ? 'justify-start' : 'justify-end'} animate-in slide-in-from-bottom-2 duration-300`}>
                            <div className={`max-w-[85%] px-4 py-2 rounded-2xl text-sm ${
                              msg.sender === 'customer' 
                              ? 'bg-white border border-slate-200 text-slate-800' 
                              : 'bg-blue-600 text-white'
                            }`}>
                              {msg.text}
                            </div>
                          </div>
                        ))}
                        {isSimulating && simStep < scenario.conversation.length && (
                          <div className="flex justify-center py-2 italic text-slate-400 text-xs">AI is replying...</div>
                        )}
                      </div>
                    </div>

                    {/* COLUMN 2: AI HANDLES (CHECKLIST) */}
                    <div className="flex flex-col h-full bg-blue-50 rounded-2xl p-4 border border-blue-100">
                      <div className="flex items-center mb-4 space-x-2">
                        <Zap size={18} className="text-blue-600" />
                        <h4 className="font-bold text-blue-900">What AI Automates</h4>
                      </div>
                      <div className="space-y-3 overflow-y-auto">
                        {scenario.aiActions.map((action, i) => {
                          const isActive = simStep >= (i / scenario.aiActions.length) * scenario.conversation.length;
                          return (
                            <div key={i} className={`flex items-center space-x-3 p-3 rounded-xl transition-all ${isActive ? 'bg-white shadow-sm' : 'opacity-40'}`}>
                              <CheckCircle2 size={20} className={isActive ? 'text-green-500' : 'text-slate-300'} />
                              <span className={`text-sm font-medium ${isActive ? 'text-slate-800' : 'text-slate-400'}`}>{action}</span>
                            </div>
                          );
                        })}
                      </div>
                    </div>

                    {/* COLUMN 3: OWNER WOULD DO (MANUAL TASKS) */}
                    <div className="flex flex-col h-full bg-red-50 rounded-2xl p-4 border border-red-100">
                      <div className="flex items-center mb-4 space-x-2">
                        <XCircle size={18} className="text-red-500" />
                        <h4 className="font-bold text-red-900">Manual Work (Replaced)</h4>
                      </div>
                      <div className="space-y-3 overflow-y-auto">
                        {scenario.manualTasks.map((task, i) => {
                          const isCrossed = simStep >= (i / scenario.manualTasks.length) * scenario.conversation.length;
                          return (
                            <div key={i} className={`flex items-center space-x-3 p-3 rounded-xl transition-all ${isCrossed ? 'opacity-30' : ''}`}>
                              <XCircle size={20} className="text-red-300" />
                              <span className={`text-sm font-medium ${isCrossed ? 'line-through' : 'text-slate-700'}`}>{task}</span>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  </div>

                  {/* CONCLUSION BANNER */}
                  {simStep >= scenario.conversation.length && (
                    <div className="bg-slate-900 text-white p-8 rounded-2xl flex flex-col md:flex-row items-center justify-between space-y-6 md:space-y-0 animate-in fade-in slide-in-from-bottom duration-700">
                      <div>
                        <h4 className="text-xl font-bold mb-2">Journey Complete. </h4>
                        <p className="text-slate-400">The customer is booked, paid, and confirmed. You didn't lift a finger.</p>
                      </div>
                      <div className="flex flex-col sm:flex-row space-y-3 sm:space-y-0 sm:space-x-4">
                        <button className="bg-blue-600 hover:bg-blue-700 px-6 py-3 rounded-lg font-bold transition-all">
                          Get this exact flow
                        </button>
                        <button onClick={handleReset} className="text-slate-400 hover:text-white transition-colors">
                          Try another scenario
                        </button>
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      </section>

      {/* 3. RESULTS PANEL (LIVE CALCULATOR) */}
      <section className="py-20 bg-white">
        <div className="max-w-6xl mx-auto px-4">
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-16 items-center">
            <div>
              <h2 className="text-3xl font-bold mb-6">See your impact instantly.</h2>
              <p className="text-slate-600 mb-8">Adjust these numbers to see how much time and revenue you're currently leaving on the table.</p>

              <div className="space-y-6">
                <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200">
                  <label className="block text-sm font-bold text-slate-700 mb-2 uppercase tracking-wide">Average Booking Value (€)</label>
                  <input 
                    type="number" 
                    value={metrics.avgBookingValue} 
                    onChange={(e) => setMetrics({...metrics, avgBookingValue: Number(e.target.value)})}
                    className="w-full bg-white border border-slate-200 rounded-lg px-4 py-3 text-xl font-bold focus:ring-2 focus:ring-blue-500 focus:outline-none"
                  />
                </div>
                <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200">
                  <label className="block text-sm font-bold text-slate-700 mb-2 uppercase tracking-wide">New Leads per Week</label>
                  <input 
                    type="number" 
                    value={metrics.leadsPerWeek} 
                    onChange={(e) => setMetrics({...metrics, leadsPerWeek: Number(e.target.value)})}
                    className="w-full bg-white border border-slate-200 rounded-lg px-4 py-3 text-xl font-bold focus:ring-2 focus:ring-blue-500 focus:outline-none"
                  />
                </div>
                <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200">
                  <label className="block text-sm font-bold text-slate-700 mb-2 uppercase tracking-wide">Missed Calls/DMs per Week</label>
                  <input 
                    type="number" 
                    value={metrics.missedCallsPerWeek} 
                    onChange={(e) => setMetrics({...metrics, missedCallsPerWeek: Number(e.target.value)})}
                    className="w-full bg-white border border-slate-200 rounded-lg px-4 py-3 text-xl font-bold focus:ring-2 focus:ring-blue-500 focus:outline-none"
                  />
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
              <div className="bg-blue-600 text-white p-8 rounded-3xl flex flex-col justify-between h-64 shadow-xl shadow-blue-100">
                <Clock className="w-10 h-10 opacity-50 mb-4" />
                <div>
                  <div className="text-4xl font-extrabold mb-1">{calculatedStats.hoursSaved}h</div>
                  <div className="text-blue-100 font-medium">Free time saved weekly</div>
                </div>
              </div>
              <div className="bg-slate-900 text-white p-8 rounded-3xl flex flex-col justify-between h-64 shadow-xl shadow-slate-100">
                <TrendingUp className="w-10 h-10 text-green-400 mb-4" />
                <div>
