                      </div>
                      <div className="flex-1 overflow-y-auto space-y-4 pr-2 custom-scrollbar">
                        {scenario.conversation.slice(0, simStep).map((msg, i) => (
                          <div key={i} className={`flex ${msg.sender === 'customer' ? 'justify-start' : 'justify-end'} animate-in slide-in-from-bottom-2 duration-300`}>
