export const getScenario = (business: BusinessType, entry: EntryPoint, intent: Intent): SimulationScenario => {
  // 1. Try to find a specific match for business + intent
  let match = SCENARIOS.find(s => s.businessType === business && s.intent === intent);

  // 2. Fallback to business match
  if (!match) {
    match = SCENARIOS.find(s => s.businessType === business) || SCENARIOS[0];
  }

  // 3. Clone and Refine: Modify the first message to match the selected entry point
  const refined = JSON.parse(JSON.stringify(match)) as SimulationScenario;
  refined.entryPoint = entry;
  refined.intent = intent;

  const firstMsg = refined.conversation[0];
  if (firstMsg) {
    switch (entry) {
      case 'Instagram DM':
        firstMsg.text = `Hey! Saw your latest post. ${firstMsg.text.split('. ').slice(1).join('. ')}`;
        break;
      case 'WhatsApp Message':
        firstMsg.text = `Hi! I found your number. ${firstMsg.text.split('. ').slice(1).join('. ')}`;
        break;
      case 'Website Chat':
        firstMsg.text = `Hello! I'm on your website. ${firstMsg.text.split('. ').slice(1).join('. ')}`;
        break;
      case 'Website Contact Form':
        firstMsg.text = `[New Submission] Name: Alex. Message: ${firstMsg.text}`;
        break;
      case 'Referral Call':
        firstMsg.text = `Hi, my friend told me about you. ${firstMsg.text.split('. ').slice(1).join('. ')}`;
        break;
      case 'Google Maps "Call Now"':
        firstMsg.text = `Hi, I found you on Google Maps. ${firstMsg.text.split('. ').slice(1).join('. ')}`;
        break;
    }
  }

  return refined;
};

import React, { useState, useEffect, useMemo } from 'react';
