  const calculatedStats = useMemo(() => {
    const weeklySavingsMinutes = metrics.leadsPerWeek * 15;
    const recoveredRevenue = metrics.missedCallsPerWeek * 0.4 * metrics.avgBookingValue;
    const monthlyRevenueImpact = (recoveredRevenue * 4) + (metrics.leadsPerWeek * metrics.avgBookingValue * 0.15 * 4);

    return {
      hoursSaved: Math.round(weeklySavingsMinutes / 60),
      revenueImpact: Math.round(monthlyRevenueImpact)
    };
