                    />
                  </div>
                </div>
                <div className="bg-slate-50 p-6 md:p-8 rounded-[1.5rem] md:rounded-[2rem] border border-slate-200 focus-within:ring-4 focus-within:ring-blue-100 transition-all">
                  <label className="block text-[10px] font-black text-slate-400 mb-4 uppercase tracking-[0.2em]">New Inquiries / Week</label>
                  <input 
                    type="number" 
                    value={metrics.leadsPerWeek} 
                    onChange={(e) => setMetrics({...metrics, leadsPerWeek: Number(e.target.value)})}
                    className="w-full bg-transparent text-3xl md:text-4xl font-black text-slate-900 focus:outline-none"
                  />
                </div>
                <div className="bg-slate-50 p-6 md:p-8 rounded-[1.5rem] md:rounded-[2rem] border border-slate-200 sm:col-span-2 focus-within:ring-4 focus-within:ring-blue-100 transition-all">
                  <label className="block text-[10px] font-black text-slate-400 mb-4 uppercase tracking-[0.2em]">Unanswered Calls / DMs / Forms</label>
                  <input 
                    type="number" 
                    value={metrics.missedCallsPerWeek} 
                    onChange={(e) => setMetrics({...metrics, missedCallsPerWeek: Number(e.target.value)})}
                    className="w-full bg-transparent text-3xl md:text-4xl font-black text-slate-900 focus:outline-none"
                  />
                </div>
              </div>
            </div>

            <div className="order-1 lg:order-2 grid grid-cols-1 sm:grid-cols-2 gap-6 md:gap-8">
              <div className="bg-blue-600 text-white p-8 md:p-10 rounded-[2rem] md:rounded-[2.5rem] flex flex-col justify-between h-64 md:h-72 shadow-2xl shadow-blue-200 transition-transform hover:-translate-y-2 duration-500">
                <Clock className="w-10 h-10 md:w-12 md:h-12 opacity-30 mb-4" />
                <div>
                  <div className="text-5xl md:text-6xl font-black mb-1 leading-none">{calculatedStats.hoursSaved}h</div>
                  <div className="text-blue-100 font-bold text-sm md:text-lg uppercase tracking-wider">Free Hours / Week</div>
                </div>
              </div>
              <div className="bg-slate-900 text-white p-8 md:p-10 rounded-[2rem] md:rounded-[2.5rem] flex flex-col justify-between h-64 md:h-72 shadow-2xl shadow-slate-200 transition-transform hover:-translate-y-2 duration-500">
                <TrendingUp className="w-10 h-10 md:w-12 md:h-12 text-green-400 mb-4" />
                <div>
                  <div className="text-4xl md:text-5xl font-black mb-1 leading-none">€{calculatedStats.revenueImpact.toLocaleString()}</div>
                  <div className="text-slate-400 font-bold text-sm md:text-lg uppercase tracking-wider">Monthly Increase</div>
                </div>
              </div>
              <div className="bg-green-500 text-white p-8 md:p-10 rounded-[2rem] md:rounded-[2.5rem] flex flex-col justify-between h-64 md:h-72 shadow-2xl shadow-green-200 sm:col-span-2 group">
                <ShieldCheck className="w-10 h-10 md:w-12 md:h-12 opacity-30 mb-4 transition-transform group-hover:scale-110" />
                <div>
                  <div className="text-2xl md:text-4xl font-black mb-2 leading-tight text-white">Instant Lead Conversion</div>
                  <div className="text-green-50 text-sm md:text-lg leading-relaxed font-medium">
                    Wellness clients want immediate answers. AI responds in seconds, securing the booking before they call another center.
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* 4. FOOTER & CTA */}
      <section id="contact" className="py-24 bg-slate-900 text-white overflow-hidden relative">
        <div className="max-w-4xl mx-auto px-4 text-center relative z-10">
          <h2 className="text-4xl md:text-5xl font-black mb-8 tracking-tight">Experience your new clinic assistant.</h2>
          <p className="text-lg md:text-xl text-slate-400 mb-12 max-w-2xl mx-auto leading-relaxed">
            Ready to stop the administrative headache? Book a 15-minute strategy call to map your journey.
          </p>
          <div className="flex flex-col sm:flex-row justify-center space-y-4 sm:space-y-0 sm:space-x-6 px-6">
            <button className="bg-blue-600 hover:bg-blue-700 text-white px-8 md:px-12 py-5 md:py-6 rounded-2xl font-black text-lg md:text-xl shadow-2xl transition-all w-full sm:w-auto">
              Claim Your Free Audit
            </button>
            <button className="bg-slate-800 hover:bg-slate-700 text-white px-8 md:px-12 py-5 md:py-6 rounded-2xl font-black text-lg md:text-xl transition-all w-full sm:w-auto">
              See Pricing
            </button>
          </div>

          <div className="mt-20 pt-20 border-t border-slate-800 flex flex-col md:flex-row justify-between items-center text-sm text-slate-500 space-y-8 md:space-y-0">
             <div className="flex items-center space-x-3">
               <Zap className="text-blue-500" size={24} />
               <span className="font-black text-white text-lg uppercase tracking-widest">JourneyPlayground AI</span>
             </div>
             <p className="text-center md:text-right">© 2024 AI Systems for Wellness. All rights reserved.</p>
          </div>
        </div>
        {/* Abstract background */}
        <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none overflow-hidden">
          <div className="absolute top-1/4 left-1/4 w-64 md:w-96 h-64 md:h-96 bg-blue-600 rounded-full blur-[120px] md:blur-[160px]"></div>
          <div className="absolute bottom-1/4 right-1/4 w-64 md:w-96 h-64 md:h-96 bg-green-600 rounded-full blur-[120px] md:blur-[160px]"></div>
        </div>
      </section>
    </div>
  );
};

export default App;

export type BusinessType = 
  | 'Wellness Center' 
  | 'Chiropractor' 
  | 'Holistic Therapist' 
  | 'Yoga Studio' 
  | 'Spa & MedSpa' 
  | 'Counseling Service';

export type EntryPoint = 
  | 'Google Maps "Call Now"'
  | 'Website Chat'
  | 'Website Contact Form'
  | 'WhatsApp Message'
  | 'Instagram DM'
  | 'Referral Call';

export type Intent = 
  | 'Book Appointment'
  | 'Ask a Question'
  | 'Get a Quote'
  | 'Pay / Deposit'
  | 'Reschedule / Cancel';

export interface ChatMessage {
  sender: 'customer' | 'ai';
  text: string;
}

export interface SimulationScenario {
  id: string;
  businessType: BusinessType;
  entryPoint: EntryPoint;
  intent: Intent;
  conversation: ChatMessage[];
  aiActions: string[];
  manualTasks: string[];
  metrics: {
    minutesSaved: number;
    missedCallRecovery: boolean;
    revenuePotential: number;
  };
}

export interface UserMetrics {
  avgBookingValue: number;
  leadsPerWeek: number;
  missedCallsPerWeek: number;
  avgSessionsPerClient: number;
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Building2, 
  MessageSquare, 
  Calendar, 
  Clock, 
  TrendingUp, 
  Zap, 
  Phone, 
  Mail, 
  MapPin, 
  RotateCcw,
  CheckCircle2,
  XCircle,
  ArrowRight,
  ShieldCheck,
  Instagram,
  Users,
  Flower2,
  Activity,
  Sun,
  Sparkles,
  Waves,
  Heart,
  Repeat
} from 'lucide-react';
import { BusinessType, EntryPoint, Intent, UserMetrics, SimulationScenario } from './types';
import { getScenario } from './constants/scenarios';

const App: React.FC = () => {
  // --- UI State ---
  const [activeStep, setActiveStep] = useState<number>(1);
  const [selectedBusiness, setSelectedBusiness] = useState<BusinessType | null>(null);
  const [selectedEntry, setSelectedEntry] = useState<EntryPoint | null>(null);
  const [selectedIntent, setSelectedIntent] = useState<Intent | null>(null);
  const [isSimulating, setIsSimulating] = useState(false);
  const [simStep, setSimStep] = useState(0);

  // --- Metrics State ---
  const [metrics, setMetrics] = useState<UserMetrics>({
    avgBookingValue: 125,
    leadsPerWeek: 35,
    missedCallsPerWeek: 8,
    avgSessionsPerClient: 3
  });

  const scenario = useMemo(() => {
    if (!selectedBusiness || !selectedEntry || !selectedIntent) return null;
    return getScenario(selectedBusiness, selectedEntry, selectedIntent);
  }, [selectedBusiness, selectedEntry, selectedIntent]);

  const simulationComplete = useMemo(() => {
    return scenario && simStep >= scenario.conversation.length;
  }, [scenario, simStep]);

  // --- Icons Map ---
  const businessIcons: Record<BusinessType, React.ElementType> = {
    'Wellness Center': Flower2,
    'Chiropractor': Activity,
    'Holistic Therapist': Sun,
    'Yoga Studio': Sparkles,
    'Spa & MedSpa': Waves,
    'Counseling Service': Heart
  };

  // --- Handlers ---
  const handleReset = () => {
    setActiveStep(1);
    setSelectedBusiness(null);
    setSelectedEntry(null);
    setSelectedIntent(null);
    setIsSimulating(false);
    setSimStep(0);
  };

  const startSimulation = () => {
    setIsSimulating(true);
    setSimStep(0);
  };

  useEffect(() => {
    if (isSimulating && scenario && simStep < scenario.conversation.length) {
      const timer = setTimeout(() => {
        setSimStep(prev => prev + 1);
      }, 1400);
      return () => clearTimeout(timer);
    }
  }, [isSimulating, simStep, scenario]);

  // --- ROI Calculation ---
  const calculatedStats = useMemo(() => {
    const weeklySavingsMinutes = metrics.leadsPerWeek * 15;

    // Revenue logic including recurring session multiplier
    const clientLifetimeValue = metrics.avgBookingValue * metrics.avgSessionsPerClient;

    // Recovered Revenue: Missed calls * recovery rate (40%) * LTV
    const weeklyRecovered = metrics.missedCallsPerWeek * 0.4 * clientLifetimeValue;

    // Conversion Boost: Total weekly inquiries * boost (15%) * LTV
    const weeklyBoost = metrics.leadsPerWeek * 0.15 * clientLifetimeValue;

    const monthlyRevenueImpact = (weeklyRecovered + weeklyBoost) * 4;

    return {
      hoursSaved: Math.round(weeklySavingsMinutes / 60),
      revenueImpact: Math.round(monthlyRevenueImpact)
    };
  }, [metrics]);

  return (
    <div className="min-h-screen">
      {/* 1. HERO SECTION */}
      <header className="bg-white border-b border-slate-200">
        <div className="max-w-6xl mx-auto px-4 py-12 md:py-24 flex flex-col items-center text-center">
          <div className="inline-flex items-center space-x-2 bg-blue-50 text-blue-600 px-3 py-1 rounded-full text-sm font-semibold mb-6">
            <Zap size={16} />
            <span>AI Customer Journey Specialist</span>
          </div>
          <h1 className="text-4xl md:text-6xl font-extrabold tracking-tight text-slate-900 mb-6 max-w-4xl leading-[1.1]">
            See how wellness clients find you — and how <span className="text-blue-600">AI handles the entire journey.</span>
          </h1>
          <p className="text-lg md:text-xl text-slate-600 mb-10 max-w-2xl leading-relaxed">
            From first inquiry to booking, deposit, and intake forms — handled 24/7 while you focus on your clients.
          </p>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12 w-full max-w-4xl text-left">
            {[
              { label: 'Time Saved', value: '15+ hours/week', desc: 'No more manual scheduling', icon: Clock },
              { label: 'Growth', value: '25% more bookings', desc: 'Instant responses win clients', icon: TrendingUp },
              { label: 'Reliability', value: '90% fewer no-shows', desc: 'Automated deposit & reminders', icon: CheckCircle2 }
            ].map((stat, i) => (
              <div key={i} className="bg-slate-50 p-6 rounded-2xl border border-slate-100 shadow-sm">
                <stat.icon className="text-blue-500 mb-3" size={28} />
                <div className="font-bold text-slate-900 text-lg">{stat.value}</div>
                <div className="text-sm text-slate-500 font-medium">{stat.desc}</div>
              </div>
            ))}
          </div>

          <div className="flex flex-col sm:flex-row space-y-4 sm:space-y-0 sm:space-x-4">
            <a href="#demo" className="bg-blue-600 hover:bg-blue-700 text-white px-10 py-5 rounded-2xl font-bold text-xl shadow-lg shadow-blue-200 transition-all flex items-center justify-center">
              Try the Journey Demo
              <ArrowRight className="ml-2" size={24} />
            </a>
          </div>
        </div>
      </header>

      {/* 2. INTERACTIVE JOURNEY PLAYGROUND */}
      <section id="demo" className="py-20 bg-slate-50">
        <div className="max-w-6xl mx-auto px-4">
          <div className="text-center mb-16">
            <h2 className="text-4xl font-black mb-4 tracking-tight">Interactive Simulation</h2>
            <p className="text-slate-600 text-lg">Select your scenario and witness the automated customer flow in action.</p>
          </div>

          <div className="bg-white rounded-[2rem] md:rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-200">
            {/* Steps Navigation */}
            <div className="bg-slate-50 border-b border-slate-200 flex overflow-x-auto no-scrollbar">
              {[
                { id: 1, label: 'Wellness Business' },
                { id: 2, label: 'Entry Point' },
                { id: 3, label: 'Their Goal' },
                { id: 4, label: 'Simulation' }
              ].map((step) => (
                <button
                  key={step.id}
                  onClick={() => step.id <= activeStep && setActiveStep(step.id)}
                  disabled={step.id > activeStep && !isSimulating}
                  className={`flex-1 min-w-[180px] py-6 px-6 text-sm font-black border-r border-slate-200 transition-all uppercase tracking-widest ${
                    activeStep === step.id 
                    ? 'bg-white text-blue-600 border-b-4 border-b-blue-600' 
                    : 'text-slate-400 cursor-default'
                  }`}
                >
                  <span className="opacity-40 mr-1.5">{step.id}.</span> {step.label}
                </button>
              ))}
            </div>

            <div className="p-6 md:p-10">
              {/* STEP 1: BUSINESS TYPE */}
              {activeStep === 1 && (
                <div className="grid grid-cols-2 lg:grid-cols-3 gap-4 md:gap-8 animate-in fade-in zoom-in-95 duration-500">
                  {Object.entries(businessIcons).map(([type, Icon]) => (
                    <button
                      key={type}
                      onClick={() => {
                        setSelectedBusiness(type as BusinessType);
                        setActiveStep(2);
                      }}
                      className="p-6 md:p-10 border-2 border-slate-100 rounded-[2rem] hover:border-blue-500 hover:bg-blue-50 transition-all text-center flex flex-col items-center justify-center space-y-4 group shadow-sm hover:shadow-xl"
                    >
                      <div className="bg-slate-50 p-4 md:p-6 rounded-3xl group-hover:bg-white transition-colors">
                        <Icon className="w-10 h-10 md:w-16 md:h-16 text-slate-400 group-hover:text-blue-600 transition-colors" />
                      </div>
                      <span className="font-black text-sm md:text-xl text-slate-800 tracking-tight leading-tight">{type}</span>
                    </button>
                  ))}
                </div>
              )}

              {/* STEP 2: ENTRY POINT */}
              {activeStep === 2 && (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4 md:gap-8 animate-in slide-in-from-right duration-500">
                  {[
                    { name: 'Google Maps "Call Now"', icon: MapPin },
                    { name: 'Website Chat', icon: MessageSquare },
                    { name: 'Website Contact Form', icon: Mail },
                    { name: 'WhatsApp Message', icon: Phone },
                    { name: 'Instagram DM', icon: Instagram },
                    { name: 'Referral Call', icon: Users }
                  ].map((entry) => (
                    <button
                      key={entry.name}
                      onClick={() => {
                        setSelectedEntry(entry.name as EntryPoint);
                        setActiveStep(3);
                      }}
                      className="p-6 md:p-8 border-2 border-slate-100 rounded-[2rem] hover:border-blue-500 hover:bg-blue-50 transition-all text-left flex items-start space-x-6 group shadow-sm hover:shadow-xl"
                    >
                      <div className="bg-slate-100 p-4 rounded-2xl group-hover:bg-blue-100 flex-shrink-0">
                        <entry.icon className="w-6 h-6 md:w-8 md:h-8 text-slate-600 group-hover:text-blue-600" />
                      </div>
                      <div>
                        <span className="font-black block text-sm md:text-lg text-slate-800 mb-1 leading-tight">{entry.name}</span>
                        <span className="text-[10px] md:text-xs text-slate-400 font-bold uppercase tracking-widest">Entry Point</span>
                      </div>
                    </button>
                  ))}
                </div>
              )}

              {/* STEP 3: INTENT */}
              {activeStep === 3 && (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4 md:gap-6 animate-in slide-in-from-right duration-500">
                  {['Book Appointment', 'Ask a Question', 'Get a Quote', 'Pay / Deposit', 'Reschedule / Cancel'].map((intent) => (
                    <button
                      key={intent}
                      onClick={() => {
                        setSelectedIntent(intent as Intent);
                        setActiveStep(4);
                        startSimulation();
                      }}
                      className="p-6 md:p-8 border-2 border-slate-100 rounded-[2rem] hover:border-blue-500 hover:bg-blue-50 transition-all text-center flex flex-col items-center justify-center space-y-4 group shadow-sm hover:shadow-xl"
                    >
                      <div className="bg-slate-50 p-3 rounded-2xl group-hover:bg-white transition-colors flex-shrink-0">
                        <Calendar className="w-6 h-6 md:w-10 md:h-10 text-slate-400 group-hover:text-blue-600" />
                      </div>
                      <span className="font-black text-xs md:text-sm text-slate-800 leading-tight uppercase tracking-tight">{intent}</span>
                    </button>
                  ))}
                </div>
              )}

              {/* STEP 4: SIMULATION */}
              {activeStep === 4 && scenario && (
                <div className="space-y-6 md:space-y-10 animate-in zoom-in-95 duration-500">
                  <div className="flex flex-col md:flex-row justify-between items-center bg-blue-50 p-6 md:p-8 rounded-[2rem] border border-blue-100">
                    <div className="flex items-center space-x-6 mb-6 md:mb-0">
                      <div className="bg-blue-600 p-4 rounded-3xl shadow-lg shadow-blue-200">
                         {React.createElement(businessIcons[selectedBusiness!] || Building2, { className: 'text-white w-8 h-8' })}
                      </div>
                      <div>
                        <h3 className="text-xl md:text-2xl font-black text-slate-900 leading-tight">{selectedBusiness} Journey</h3>
                        <p className="text-xs md:text-base text-blue-600 font-bold uppercase tracking-widest">{selectedEntry} • {selectedIntent}</p>
                      </div>
                    </div>
                    <button onClick={handleReset} className="flex items-center bg-white px-6 py-3 rounded-2xl text-slate-400 hover:text-slate-800 transition-all font-black text-[10px] md:text-sm uppercase tracking-[0.2em] shadow-sm border border-slate-100">
                      <RotateCcw size={16} className="mr-2" />
                      Reset Demo
                    </button>
                  </div>

                  <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 md:gap-8 h-auto lg:h-[650px]">
                    {/* CUSTOMER VIEW */}
                    <div className="flex flex-col h-[450px] lg:h-full bg-slate-900 rounded-[2rem] md:rounded-[2.5rem] p-6 md:p-8 shadow-2xl border border-slate-800">
                      <div className="flex items-center justify-between mb-8 border-b border-slate-800 pb-6">
                        <div className="flex items-center space-x-4">
                          <div className="w-12 h-12 rounded-2xl bg-slate-800 border border-slate-700 flex items-center justify-center text-white font-black text-lg">C</div>
                          <div>
                            <p className="text-white font-black text-base">New Client</p>
                            <p className="text-green-500 text-[10px] font-bold uppercase tracking-widest animate-pulse">Online</p>
                          </div>
                        </div>
                        <div className="bg-slate-800 p-3 rounded-xl border border-slate-700">
                          <MessageSquare size={18} className="text-blue-500" />
                        </div>
                      </div>
                      <div className="flex-1 overflow-y-auto space-y-6 pr-2 custom-scrollbar">
                        {scenario.conversation.slice(0, simStep).map((msg, i) => (
                          <div key={i} className={`flex ${msg.sender === 'customer' ? 'justify-start' : 'justify-end'} animate-in slide-in-from-bottom-2 duration-500`}>
                            <div className={`max-w-[88%] px-5 py-4 rounded-3xl text-sm md:text-base leading-relaxed font-medium ${
                              msg.sender === 'customer' 
                              ? 'bg-slate-800 text-slate-200 rounded-tl-none border border-slate-700' 
                              : 'bg-blue-600 text-white rounded-tr-none shadow-xl shadow-blue-900/30'
                            }`}>
                              {msg.text}
                            </div>
                          </div>
                        ))}
                        {isSimulating && simStep < scenario.conversation.length && (
                          <div className="flex justify-start items-center space-x-3 ml-2 opacity-50">
                             <div className="flex space-x-1.5 bg-slate-800 px-4 py-3 rounded-2xl border border-slate-700">
                                <div className="w-2 h-2 bg-blue-500 rounded-full animate-bounce delay-75"></div>
                                <div className="w-2 h-2 bg-blue-500 rounded-full animate-bounce delay-150"></div>
                                <div className="w-2 h-2 bg-blue-500 rounded-full animate-bounce delay-300"></div>
                             </div>
                          </div>
                        )}
                      </div>
                    </div>

                    {/* AI ACTIONS */}
