                            <div key={i} className={`flex items-start space-x-4 p-5 rounded-3xl transition-all duration-700 border ${isActive ? 'bg-white shadow-xl border-white scale-100 opacity-100' : 'opacity-20 border-transparent scale-95'}`}>
