          <div className="grid grid-cols-1 lg:grid-cols-2 gap-16 md:gap-24 items-start">
            <div className="space-y-8">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 md:gap-8">
                {/* 1. Missed Calls (First as requested) */}
                <div className="bg-slate-50 p-8 rounded-[2rem] border border-slate-200 focus-within:ring-4 focus-within:ring-blue-100 transition-all shadow-sm">
