                  <div className="flex items-center">
                    <span className="text-2xl font-black text-slate-300 mr-2">€</span>
                    <input 
                      type="number" 
                      value={metrics.avgBookingValue} 
                      onChange={(e) => setMetrics({...metrics, avgBookingValue: Number(e.target.value)})}
                      className="w-full bg-transparent text-4xl font-black text-slate-900 focus:outline-none"
                    />
                  </div>
                </div>

                {/* 3. New Inquiries */}
                <div className="bg-slate-50 p-8 rounded-[2rem] border border-slate-200 focus-within:ring-4 focus-within:ring-blue-100 transition-all shadow-sm">
                  <label className="flex items-center text-[10px] font-black text-slate-400 mb-4 uppercase tracking-[0.2em]">
                    <Users size={12} className="mr-2 text-green-400" />
                    New Inquiries / Week
                  </label>
                  <input 
                    type="number" 
                    value={metrics.leadsPerWeek} 
                    onChange={(e) => setMetrics({...metrics, leadsPerWeek: Number(e.target.value)})}
                    className="w-full bg-transparent text-4xl font-black text-slate-900 focus:outline-none"
                  />
                </div>

                {/* 4. Multiplier for Recurring Clients */}
                <div className="bg-slate-50 p-8 rounded-[2rem] border border-slate-200 focus-within:ring-4 focus-within:ring-blue-100 transition-all shadow-sm">
                  <label className="flex items-center text-[10px] font-black text-slate-400 mb-4 uppercase tracking-[0.2em]">
                    <Repeat size={12} className="mr-2 text-purple-400" />
                    Avg. Sessions Per Client
                  </label>
                  <input 
                    type="number" 
                    step="0.1"
                    value={metrics.avgSessionsPerClient} 
                    onChange={(e) => setMetrics({...metrics, avgSessionsPerClient: Number(e.target.value)})}
                    className="w-full bg-transparent text-4xl font-black text-slate-900 focus:outline-none"
                  />
                </div>
              </div>
              <p className="text-slate-400 text-sm italic font-medium">
                * Based on a 40% recovery rate of missed inquiries and a 15% increase in lead-to-booking conversion using AI.
              </p>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-8">
              <div className="bg-blue-600 text-white p-10 rounded-[2.5rem] flex flex-col justify-between h-72 shadow-2xl shadow-blue-200 transition-all hover:scale-[1.02] duration-500">
                <Clock className="w-12 h-12 opacity-30 mb-4" />
                <div>
                  <div className="text-6xl font-black mb-2 tracking-tighter leading-none">{calculatedStats.hoursSaved}h</div>
                  <div className="text-blue-100 font-black text-lg uppercase tracking-wider leading-tight">Admin Hours Saved / Week</div>
                </div>
              </div>
              <div className="bg-slate-900 text-white p-10 rounded-[2.5rem] flex flex-col justify-between h-72 shadow-2xl shadow-slate-300 transition-all hover:scale-[1.02] duration-500">
                <TrendingUp className="w-12 h-12 text-green-400 mb-4" />
                <div>
                  <div className="text-5xl md:text-6xl font-black mb-2 tracking-tighter leading-none">€{calculatedStats.revenueImpact.toLocaleString()}</div>
                  <div className="text-slate-400 font-black text-lg uppercase tracking-wider leading-tight">Monthly Growth Boost</div>
                </div>
              </div>
              <div className="bg-green-500 text-white p-10 rounded-[3rem] flex flex-col justify-between h-72 shadow-2xl shadow-green-100 sm:col-span-2 group">
                <ShieldCheck className="w-14 h-14 opacity-30 mb-4 transition-transform group-hover:rotate-12" />
                <div>
                  <div className="text-3xl md:text-4xl font-black mb-3 tracking-tighter leading-none">Instant Lead Capture</div>
                  <div className="text-green-50 text-base md:text-xl leading-relaxed font-bold">
                    Wellness clients value time. AI answers in seconds, securing the booking and the <span className="underline decoration-white decoration-2 underline-offset-4">recurring lifetime value</span> before they call a competitor.
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* 4. FOOTER & CTA */}
      <section id="contact" className="py-24 bg-slate-900 text-white overflow-hidden relative border-t border-slate-800">
        <div className="max-w-4xl mx-auto px-6 text-center relative z-10">
          <h2 className="text-4xl md:text-6xl font-black mb-10 tracking-tighter leading-tight">Ready to reclaim your <span className="text-blue-500">desk-time?</span></h2>
          <p className="text-xl md:text-2xl text-slate-400 mb-14 max-w-2xl mx-auto leading-relaxed font-medium">
            Stop losing leads to manual admin. Book a 15-minute strategy call to map your new automated journey.
          </p>
          <div className="flex flex-col sm:flex-row justify-center space-y-6 sm:space-y-0 sm:space-x-8 px-4">
            <button className="bg-blue-600 hover:bg-blue-700 text-white px-12 md:px-16 py-6 md:py-8 rounded-[2rem] font-black text-xl md:text-2xl shadow-2xl transition-all w-full sm:w-auto transform hover:-translate-y-2 active:scale-95 shadow-blue-500/20">
              Claim Free Audit
            </button>
            <button className="bg-slate-800 hover:bg-slate-700 text-white px-12 md:px-16 py-6 md:py-8 rounded-[2rem] font-black text-xl md:text-2xl transition-all w-full sm:w-auto">
