            <div className="grid grid-cols-1 sm:grid-cols-2 gap-8 sticky top-12">
              <div className="bg-blue-600 text-white p-14 rounded-[3.5rem] flex flex-col justify-between h-96 shadow-3xl shadow-blue-200 transition-all hover:-rotate-1 duration-500">
