                <div className="relative z-10">
                  <div className="text-5xl md:text-6xl font-black mb-6 tracking-tighter leading-[0.85]">The AI Multiplier</div>
                  <div className="text-green-50 text-2xl leading-relaxed font-bold max-w-2xl">
                    Every missed call is a lost recurring relationship. AI secures the <span className="underline decoration-white decoration-4 underline-offset-[12px]">lifetime value</span> of your practice 24/7.
                  </div>
                </div>
                <div className="absolute top-0 right-0 w-[400px] h-[400px] bg-white/10 rounded-full blur-[100px] -translate-y-1/2 translate-x-1/2"></div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* 4. FOOTER & CTA */}
      <section id="contact" className="py-32 bg-slate-900 text-white relative border-t border-slate-800">
