                  </div>
                  <input 
                    type="range" 
                    min="0" 
                    max="150" 
                    step="5"
                    value={metrics.leadsPerWeek} 
                    onChange={(e) => setMetrics({...metrics, leadsPerWeek: Number(e.target.value)})}
                    className="w-full h-3 bg-slate-100 rounded-lg appearance-none cursor-pointer accent-blue-600"
                  />
